                    </div>

                    {/* Navigation Tabs (Glassmorphic) */}
                    <div className="flex bg-white/5 backdrop-blur-md rounded-2xl p-1.5 border border-white/10">
                        {[
                            { id: 'performance', label: 'Dashboard', icon: Target },
