                        <Dna size={24} className="text-emerald-400" />
                    </div>
                    {!sidebarCollapsed && (
                        <div>
                            <h1 className="font-bold text-lg leading-tight tracking-wider group-hover/brand:text-emerald-300 transition-colors" style={{ fontFamily: "'Audiowide', sans-serif" }}>PRIMER</h1>
                            <p className="text-[10px] text-emerald-200 opacity-80 uppercase tracking-widest">{APP_METADATA.fullName}</p>
                        </div>
                    )}
                </div>

                {/* RPG Avatar Profile (The "Hero") */}
                <div className={`${sidebarCollapsed ? 'p-1' : 'p-4'} border-b border-white/10 relative group transition-all`}>
                    <div
                        className={`flex items-center gap-3 ${sidebarCollapsed ? 'justify-center' : ''} cursor-pointer hover:brightness-110 transition-all`}
                        title="Click to view Status/Junction"
                        onClick={() => setShowStatus(true)}
                    >
                        {/* Avatar Circle with XP Ring */}
                        <div className="relative w-12 h-12 flex-shrink-0 cursor-help">
                            {/* XP Ring SVG */}
                            <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 36 36">
                                <path
                                    className="text-white/10"
                                    d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                                    fill="none"
                                    stroke="currentColor"
                                    strokeWidth="3"
                                />
                                <path
                                    className="text-amber-400 transition-all duration-1000 ease-out"
                                    strokeDasharray={`${xpPercentage}, 100`}
                                    d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                                    fill="none"
                                    stroke="currentColor"
                                    strokeWidth="3"
                                />
                            </svg>

                            {/* Avatar Icons */}
                            <div className="absolute inset-1 rounded-full bg-slate-800 flex items-center justify-center overflow-hidden border-2 border-slate-600">
                                <AvatarRenderer avatar={playerProfile?.avatar} size={36} />
                            </div>

                            {/* Level Badge */}
                            <div className="absolute -bottom-1 -right-1 bg-red-600 text-white text-[10px] font-bold px-1.5 rounded-full border border-slate-900 shadow-sm">
                                Lv.{playerStats.level}
                            </div>
                        </div>

                        {!sidebarCollapsed && (
                            <div className="overflow-hidden flex-1">
                                <p className="font-bold text-sm truncate">{playerProfile?.name || 'Dr. Player'}</p>
                                <div className="text-xs text-emerald-300 flex items-center gap-1">
                                    <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse"></span>
                                    Kepala Puskesmas
                                </div>
                            </div>
                        )}

                        {!sidebarCollapsed && (
                            <button
                                onClick={(e) => { e.stopPropagation(); setShowAvatarEdit(true); }}
                                className="p-1.5 rounded-full bg-white/10 hover:bg-white/20 text-white/40 hover:text-white transition-all opacity-0 group-hover:opacity-100"
                                title="Ganti Avatar"
                            >
                                <Sparkles size={14} />
                            </button>
                        )}
                    </div>
                </div>

                {/* Navigation */}
                <nav className="flex-1 py-4 overflow-y-auto overflow-x-hidden custom-scrollbar">
                    <ul className="space-y-1 px-2">
                        {menuItems.map(item => (
                            <li key={item.id} className="relative group">
                                <button
                                    onClick={() => {
                                        if (item.id === 'rumah_dinas') {
                                            setGameState('rumah_dinas');
                                        } else if (item.id === 'wiki') {
                                            openWiki('anamnesis'); // Default topic for Codex entry
                                        } else {
                                            setActivePage(item.id);
                                        }
                                    }}
                                    className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all ${sidebarCollapsed ? 'justify-center' : ''} ${activePage === item.id
                                        ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-900/20 font-medium'
                                        : item.special
                                            ? 'text-yellow-300 hover:bg-yellow-500/20 hover:text-yellow-200 border border-yellow-500/30'
                                            : 'text-slate-300 hover:bg-white/5 hover:text-white'
                                        }`}
                                >
                                    <item.icon size={20} className={activePage === item.id ? 'animate-pulse-slow' : ''} />
                                    {!sidebarCollapsed && <span>{item.label}</span>}
                                </button>
                                {/* PS-style hover label when collapsed */}
                                {sidebarCollapsed && (
                                    <div className="absolute left-full ml-3 top-1/2 -translate-y-1/2 px-3 py-1.5 bg-slate-900/95 text-white text-xs font-bold rounded-lg opacity-0 group-hover:opacity-100 pointer-events-none transition-all duration-200 whitespace-nowrap z-50 shadow-xl backdrop-blur-sm">
                                        <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-0 h-0 border-t-[6px] border-t-transparent border-r-[8px] border-r-slate-900/95 border-b-[6px] border-b-transparent"></div>
                                        {item.label}
                                    </div>
                                )}
                            </li>
                        ))}
                    </ul>
                </nav>

                {/* Sidebar Footer / Personal Area */}
                <div className={`mt-auto ${sidebarCollapsed ? 'p-1' : 'p-2'} space-y-1.5 border-t border-white/10 transition-all`}>
                    <div className="relative group">
                        <button
                            onClick={() => setGameState('rumah_dinas')}
                            className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all text-yellow-300 hover:bg-yellow-500/20 hover:text-yellow-200 border border-yellow-500/20 ${sidebarCollapsed ? 'justify-center' : ''}`}
                        >
                            <Home size={20} />
                            {!sidebarCollapsed && <span className="font-bold">Rumah Dinas</span>}
                        </button>
                        {sidebarCollapsed && (
                            <div className="absolute left-full ml-3 top-1/2 -translate-y-1/2 px-3 py-1.5 bg-yellow-500 text-slate-900 text-xs font-bold rounded-lg opacity-0 group-hover:opacity-100 pointer-events-none transition-all duration-200 whitespace-nowrap z-50 shadow-xl">
                                <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-0 h-0 border-t-[6px] border-t-transparent border-r-[8px] border-r-yellow-500 border-b-[6px] border-b-transparent"></div>
                                🏠 Rumah Dinas
                            </div>
                        )}
                    </div>

                    <div className="relative group">
                        <button
                            onClick={() => setShowSettings(true)}
                            className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg transition-all text-slate-400 hover:text-white hover:bg-white/5 border border-white/5 ${sidebarCollapsed ? 'justify-center' : ''}`}
                        >
                            <Settings size={18} />
                            {!sidebarCollapsed && <span className="text-sm font-medium">Setting</span>}
                        </button>
                        {sidebarCollapsed && (
                            <div className="absolute left-full ml-3 top-1/2 -translate-y-1/2 px-3 py-1.5 bg-slate-900/95 text-white text-xs font-bold rounded-lg opacity-0 group-hover:opacity-100 pointer-events-none transition-all duration-200 whitespace-nowrap z-50 shadow-xl backdrop-blur-sm">
                                <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-0 h-0 border-t-[6px] border-t-transparent border-r-[8px] border-r-slate-900/95 border-b-[6px] border-b-transparent"></div>
                                ⚙️ Setting
                            </div>
                        )}
                    </div>

                    <div className="relative group">
                        <button
                            onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
                            className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg transition-all text-slate-500 hover:text-white hover:bg-white/5 ${sidebarCollapsed ? 'justify-center' : ''}`}
                        >
                            {sidebarCollapsed ? <ChevronRight size={18} /> : <ChevronLeft size={18} />}
                            {!sidebarCollapsed && <span className="text-xs font-medium text-slate-500">Tutup Panel</span>}
                        </button>
                        {sidebarCollapsed && (
                            <div className="absolute left-full ml-3 top-1/2 -translate-y-1/2 px-3 py-1.5 bg-slate-900/95 text-white text-xs font-bold rounded-lg opacity-0 group-hover:opacity-100 pointer-events-none transition-all duration-200 whitespace-nowrap z-50 shadow-xl backdrop-blur-sm">
                                <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-0 h-0 border-t-[6px] border-t-transparent border-r-[8px] border-r-slate-900/95 border-b-[6px] border-b-transparent"></div>
                                📂 Buka Panel
                            </div>
                        )}
                    </div>
                </div>
            </aside>

            {/* Main Content Area */}
            <main className="flex-1 flex flex-col min-w-0 bg-[var(--color-bg-main)] relative">
                {/* Top Bar */}
                <header className="bg-white border-b border-slate-200 h-16 px-6 flex items-center justify-between shadow-sm z-10 relative">
                    <div className="flex items-center gap-4">
                        <h1 className="text-3xl font-black tracking-wider text-white" style={{ fontFamily: "'Audiowide', 'Orbitron', 'Rajdhani', sans-serif", letterSpacing: '0.15em' }}>
                            PRIMER
                        </h1></div>

                    <div className="flex items-center gap-4">
                        {/* QUEST BUTTON */}
                        <div className="relative">
                            <button
                                onClick={() => setShowQuests(!showQuests)}
                                className={`flex items-center gap-2 px-3 py-1.5 rounded-full transition-all border ${showQuests ? 'bg-amber-100 border-amber-300 text-amber-800' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                                    }`}
                            >
                                <span className="text-lg">📜</span>
                                <span className="text-xs font-bold">Misi</span>
                                {hasClaimableQuests && (
                                    <span className="absolute -top-1 -right-1 flex h-3 w-3">
                                        <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                                        <span className="relative inline-flex rounded-full h-3 w-3 bg-amber-500"></span>
                                    </span>
                                )}
                            </button>

                            {/* Quest Popover */}
                            {showQuests && (
                                <div className="absolute top-12 right-0 z-50 shadow-2xl rounded-xl overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                                    <div className="max-h-[80vh] overflow-hidden flex">
                                        <QuestBoard />
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* === ENERGY BAR === */}
                        <div
                            onClick={() => openWiki('energy')}
                            className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-full border border-slate-200 cursor-pointer hover:bg-white transition-all"
                        >
                            <span className="text-lg">⚡</span>
                            <div className="w-24 h-3 bg-slate-200 rounded-full overflow-hidden">
                                <div
                                    className={`h-full transition-all duration-300 ${getEnergyColor(energy)}`}
                                    style={{ width: `${energy}%` }}
                                />
                            </div>
                            <span className="text-xs font-bold text-slate-700 w-8">{Math.round(energy)}%</span>
                        </div>

                        {/* === REPUTATION === */}
                        <div
                            onClick={() => openWiki('reputation')}
                            className="flex items-center gap-2 bg-amber-50 px-3 py-1.5 rounded-full border border-amber-200 cursor-pointer hover:bg-white transition-all"
                        >
                            <span className="text-lg">⭐</span>
                            <span className="text-xs font-bold text-amber-700">{reputation}</span>
                        </div>

                        {/* === PRB ACTIVE BADGE === */}
                        {prbQueue && prbQueue.filter(p => p.status === 'active').length > 0 && (
                            <div
                                onClick={() => setActivePage('dashboard')}
                                className="flex items-center gap-2 bg-cyan-50 px-3 py-1.5 rounded-full border border-cyan-200 cursor-pointer hover:bg-white transition-all animate-pulse"
                                title="Pasien PRB Aktif - Klik untuk melihat di Dashboard"
                            >
                                <span className="text-lg">📋</span>
                                <span className="text-xs font-bold text-cyan-700">{prbQueue.filter(p => p.status === 'active').length} PRB</span>
                            </div>
                        )}

                        {/* === COMMAND CENTER (Time & Speed) === */}
                        <div className="flex items-center bg-slate-100 rounded-full border border-slate-200 overflow-hidden shadow-sm">
                            {/* Controls */}
                            <div className="flex items-center px-2 gap-1 border-r border-slate-200 bg-white">
                                <button
                                    onClick={() => setGameState(gameState === 'playing' ? 'paused' : 'playing')}
                                    className={`p-1 rounded hover:bg-slate-100 transition ${gameState === 'paused' ? 'text-amber-500' : 'text-slate-600'}`}
                                    title={gameState === 'playing' ? 'Pause' : 'Resume'}
                                >
                                    {gameState === 'paused' ? <Play size={16} fill="currentColor" /> : <Pause size={16} fill="currentColor" />}
                                </button>
                                <button
                                    onClick={() => setGameSpeed(s => s >= 4 ? 1 : s * 2)}
                                    className="p-1 rounded hover:bg-slate-100 text-slate-600 flex items-center gap-0.5"
                                    title={`Speed: ${gameSpeed}x`}
                                >
                                    <FastForward size={16} />
                                    <span className="text-[10px] font-bold w-3">{gameSpeed}x</span>
                                </button>
                            </div>

                            {/* Time Display */}
                            <button
                                onClick={() => setShowCalendar(true)}
                                className="flex items-center gap-3 px-3 py-1.5 bg-slate-100 hover:bg-white transition-colors cursor-pointer"
                                title="Open Calendar"
                            >
                                <span className="text-xs font-bold text-indigo-600 uppercase">Hari {day}</span>
                                <div className="w-px h-3 bg-slate-300"></div>
                                <span className="font-mono font-medium text-slate-700">{formatTime(time)}</span>
                            </button>
                        </div>

                        {/* Home Button (Contextual) */}
                        {((time >= 720 && time < 780) || time >= 960) && (
                            <button
                                onClick={() => setGameState('rumah_dinas')}
                                className="flex items-center gap-2 bg-blue-600 text-white px-4 py-1.5 rounded-full hover:bg-blue-700 animate-pulse shadow-md transition-all"
                            >
                                <Home size={16} />
                                <span className="text-xs font-bold">Rumah</span>
                            </button>
                        )}

                        <div className="w-px h-6 bg-slate-200 mx-1"></div>

                        {/* SYSTEM MENU BUTTON */}
                        <div className="flex items-center gap-2">
                            <button
                                onClick={() => setShowKPIGlobal(true)}
                                className={`flex items-center gap-2 px-3 py-1.5 rounded-full transition-all border ${showKPIGlobal ? 'bg-indigo-100 border-indigo-300 text-indigo-800' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                                title="Review Kinerja (KPI)"
                            >
                                <Activity size={16} className="text-indigo-500" />
                                <span className="text-xs font-bold">Review</span>
                                {derivedKpis?.overallScore < 70 && (
                                    <span className="w-2 h-2 rounded-full bg-red-500 animate-ping"></span>
                                )}
                            </button>

                            <button
                                onClick={() => setShowSettings(true)}
                                className="flex items-center justify-center w-9 h-9 text-slate-500 hover:text-slate-800 hover:bg-slate-100 rounded-full transition-all"
                                title="System Settings"
                            >
                                <Settings size={20} />
                            </button>
                        </div>
                    </div>
                </header>

                {/* Page Content */}
                <div className="flex-1 overflow-hidden relative">
                    {/* Render Page based on state */}
                    <Suspense fallback={<PageLoader />}>
                        {activePage === 'dashboard' && (
                            <ErrorBoundary name="DashboardPage">
                                <DashboardPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'clinical' && (
                            <ErrorBoundary name="ClinicalPage">
                                <ClinicalPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'wilayah' && (
                            <ErrorBoundary name="WilayahPage">
                                <WilayahPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'facility' && (
                            <ErrorBoundary name="GedungPage">
                                <GedungPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'staff' && (
                            <ErrorBoundary name="StaffPage">
                                <StaffPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'inventory' && (
                            <ErrorBoundary name="InventoryPage">
                                <InventoryPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'academy' && (
                            <ErrorBoundary name="DiklatPage">
                                <DiklatPage />
                            </ErrorBoundary>
                        )}
                        {activePage === 'archive' && (
                            <ErrorBoundary name="ArsipPage">
                                <ArsipPage />
                            </ErrorBoundary>
                        )}
                    </Suspense>
                </div>
            </main>

            {/* Smartphone Overlay */}
            {showPhone && <Smartphone onClose={() => setShowPhone(false)} />}
            <button
                onClick={() => setShowPhone(!showPhone)}
                className="fixed bottom-6 right-6 bg-slate-800 text-white p-4 rounded-full shadow-2xl hover:bg-slate-700 hover:scale-110 transition-all z-50 border-4 border-slate-600"
            >
                <PhoneIcon size={24} />
            </button>

            {/* Lazy-loaded Modals (wrapped in Suspense) */}
            <Suspense fallback={null}>
                {/* Settings Modal */}
                {showSettings && (
                    <ErrorBoundary name="SettingsModal">
                        <SettingsModal onClose={() => setShowSettings(false)} />
                    </ErrorBoundary>
                )}

                {/* Avatar Selection Modal */}
                {showAvatarEdit && <AvatarSelectionModal onClose={() => setShowAvatarEdit(false)} />}

                {/* FF8 Status Modal */}
                {showStatus && (
                    <ErrorBoundary name="StatusJunctionModal">
                        <StatusJunctionModal onClose={() => setShowStatus(false)} onOpenWiki={openWiki} />
                    </ErrorBoundary>
                )}

                {/* Calendar Modal */}
                {showCalendar && (
                    <CalendarModal
                        currentDay={day}
                        dailyArchive={dailyArchive}
                        onSelectDay={(dayData) => {
                            setSelectedDailyReport(dayData);
                            setShowCalendar(false);
                        }}
                        onClose={() => setShowCalendar(false)}
                    />
                )}

                {/* Daily Report Modal */}
                {selectedDailyReport && (
                    <DailyReportModal
                        dayData={selectedDailyReport}
                        dailyArchive={dailyArchive}
                        onNavigate={(newData) => setSelectedDailyReport(newData)}
                        onBackToCalendar={() => {
                            setSelectedDailyReport(null);
                            setShowCalendar(true);
                        }}
                        onClose={() => setSelectedDailyReport(null)}
                    />
                )}

                {/* Global KPI Dashboard Modal */}
                {showKPIGlobal && (
                    <div className="fixed inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center z-[100] p-4 animate-in fade-in duration-300">
                        <div className="w-full max-w-5xl h-[90vh] bg-white rounded-2xl shadow-2xl relative overflow-hidden flex flex-col">
                            <button
                                onClick={() => setShowKPIGlobal(false)}
                                className="absolute top-4 right-4 z-[101] p-2 bg-white/20 hover:bg-white/40 text-white rounded-full transition-all"
                            >
                                <X size={24} />
                            </button>
                            <div className="flex-1 overflow-hidden">
                                <ErrorBoundary name="KPIDashboard">
                                    <KPIDashboard />
                                </ErrorBoundary>
                            </div>
                            <div className="bg-slate-50 p-4 border-t flex justify-end shrink-0">
                                <button
                                    onClick={() => setShowKPIGlobal(false)}
                                    className="px-6 py-2 bg-slate-800 text-white rounded-xl hover:bg-slate-900 font-bold transition-all"
                                >
                                    Selesai
                                </button>
                            </div>
                        </div>
                    </div>
                )}
                {/* Educational Wiki Modal */}
                <EducationalWikiModal
                    isOpen={isWikiOpen}
                    onClose={closeWiki}
                    metricKey={wikiMetric}
                    data={WIKI_DATA[wikiMetric]}
                    liveStats={useMemo(() => {
                        if (!wikiMetric) return null;
                        switch (wikiMetric) {
                            case 'energy':
                                return {
                                    "Level Energi": energy + "%",
                                    "Status": energy > 70 ? "Fit" : energy > 40 ? "Lelah" : "Exhausted"
                                };
                            case 'reputation':
                                return {
                                    "Skor Reputasi": reputation,
                                    "Status": reputation > 80 ? "Sangat Dipercaya" : "Cukup"
                                };
                            case 'xp_level':
                                return {
                                    "Level": playerStats.level,
                                    "XP": playerStats.xp + " / " + playerStats.nextLevelXp,
                                    "Pencapaian": "Kepala Puskesmas"
                                };
                            default:
                                return null;
                        }
                    }, [wikiMetric, energy, reputation, playerStats])}
                />
                {/* Narrative Overlay */}
                {(focusedStory || interactiveStory) && (
                    <NarrativeOverlay
                        storyInstance={focusedStory || interactiveStory}
                        onClose={() => setFocusedStory(null)}
                    />
                )}
            </Suspense>

            {/* About PRIMER Modal */}
            {showAbout && (
                <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[200] p-4 animate-in fade-in duration-300">
                    <div className={`w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh] ${isDark ? 'bg-slate-900 border border-white/10' : 'bg-white'}`}>
                        {/* Header Image/Pattern */}
                        <div className="h-32 bg-gradient-to-r from-emerald-600 to-teal-700 p-8 flex items-end relative shrink-0">
                            <button
                                onClick={() => setShowAbout(false)}
                                className="absolute top-4 right-4 p-2 bg-black/20 hover:bg-black/40 text-white rounded-full transition-all"
                            >
                                <X size={20} />
                            </button>
                            <div className="flex items-center gap-4">
                                <div className="p-2 bg-white/20 rounded-xl backdrop-blur-sm border border-white/20">
                                    <img src={getAssetUrl(ASSET_KEY.ITS_LOGO)} alt="ITS" className="h-12 w-12 object-contain drop-shadow-lg" />
                                </div>
                                <div>
                                    <h2 className="text-white text-3xl font-black tracking-tighter">PRIMER</h2>
                                    <p className="text-emerald-100 text-xs font-bold tracking-widest uppercase opacity-80">{APP_METADATA.fullName}</p>
                                </div>
                            </div>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
                            <section>
                                <h3 className={`font-black text-xs uppercase tracking-widest mb-3 flex items-center gap-2 ${isDark ? 'text-emerald-400' : 'text-emerald-700'}`}>
                                    <div className="w-4 h-1 bg-emerald-500 rounded-full"></div>
                                    Visi & Misi
                                </h3>
                                <p className={`leading-relaxed text-sm italic pl-4 ${isDark ? 'text-slate-300 border-l-4 border-slate-700' : 'text-slate-600 border-l-4 border-slate-100'}`}>
                                    "{APP_METADATA.description}"
                                </p>
                            </section>

                            <div className="grid grid-cols-2 gap-4">
                                <section className={`p-4 rounded-2xl border flex items-center gap-4 ${isDark ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-100'}`}>
                                    <img src={getAssetUrl(ASSET_KEY.ITS_LOGO)} alt="ITS" className="h-10 w-10 object-contain" />
                                    <div>
                                        <h4 className={`font-bold text-[10px] uppercase mb-1 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Kreator</h4>
                                        <p className={`font-black text-sm leading-tight ${isDark ? 'text-white' : 'text-slate-800'}`}>{APP_METADATA.creator}</p>
                                        <div className="mt-1">
                                            <p className={`font-bold text-[11px] uppercase tracking-tighter ${isDark ? 'text-emerald-400' : 'text-emerald-700'}`}>{APP_METADATA.organization}</p>
                                            <p className={`text-[10px] ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>{APP_METADATA.department}</p>
                                        </div>
                                    </div>
                                </section>
                                <section className={`p-4 rounded-2xl border ${isDark ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-100'}`}>
