/**
 * OpeningScreen — Cinematic game-like opening with logo sequence and main menu.
 * 
 * Flow:
 *  1. ITS logo fades in (colored, with glow)
 *  2. ITS logo fades out → FKK/Kedokteran logo fades in (white, with glow)
 *  3. Both logos fade out → PRIMER title + menu appears
 */
export default function OpeningScreen({ onNewGame, onContinue, hasSaveData }) {
    // Animation phases: 'its_logo' → 'its_fade' → 'fkk_logo' → 'fkk_fade' → 'menu'
    const [phase, setPhase] = useState('its_logo');
    const timersRef = useRef([]);

    // Generate particle positions once (avoid re-randomizing on each render)
    const particles = useMemo(() =>
        [...Array(25)].map(() => ({
            w: Math.random() * 3 + 1,
            x: Math.random() * 100,
            y: Math.random() * 100,
            color: Math.random() > 0.5 ? '16, 185, 129' : '99, 102, 241',
            alpha: Math.random() * 0.4 + 0.1,
            dur: 8 + Math.random() * 12,
            delay: Math.random() * 10,
        })), []
    );

    // Auto-advance through phases
    useEffect(() => {
        let t = 0;

        // Phase 1: ITS logo shows immediately, hold for 2.5s
        t += 2500;
        timersRef.current.push(setTimeout(() => setPhase('its_fade'), t));

        // Fade out ITS → show FKK
        t += 800;
        timersRef.current.push(setTimeout(() => setPhase('fkk_logo'), t));

        // Phase 2: FKK logo, hold for 2.5s
        t += 2500;
        timersRef.current.push(setTimeout(() => setPhase('fkk_fade'), t));

        // Fade out FKK → Show menu
        t += 800;
        timersRef.current.push(setTimeout(() => setPhase('menu'), t));

        return () => {
            timersRef.current.forEach(id => clearTimeout(id));
            timersRef.current = [];
        };
    }, []);

    // Clear all pending timers and skip to menu
    const skipToMenu = useCallback(() => {
        // Clear any remaining animation timers to prevent stale phase updates
        timersRef.current.forEach(id => clearTimeout(id));
        timersRef.current = [];
        setPhase('menu');
    }, []);

    useEffect(() => {
        const handleKey = (e) => {
            if (['Escape', 'Enter', ' '].includes(e.key) && phase !== 'menu') {
                skipToMenu();
            }
        };
        window.addEventListener('keydown', handleKey);
        return () => window.removeEventListener('keydown', handleKey);
    }, [skipToMenu, phase]);

    const handleClick = () => {
        soundManager.init();
        if (phase !== 'menu') skipToMenu();
    };

    const handleNewGame = (e) => {
        e.stopPropagation();
        soundManager.init();
        soundManager.playConfirm();
        onNewGame();
