                            opacity: isITS ? 1 : 0,
                            transition: 'opacity 1.5s',
                        }}
                    />
                    <img
                        src={getAssetUrl(ASSET_KEY.ITS_LOGO)}
                        alt="ITS"
                        className="h-36 w-36 object-contain relative z-10"
                        style={{ filter: 'drop-shadow(0 0 20px rgba(16,185,129,0.3))' }}
                    />
                </div>
                <p className="mt-8 text-slate-400 text-sm tracking-[0.3em] uppercase font-light"
                    style={{ opacity: isITS ? 1 : 0, transition: 'opacity 1s' }}>
                    Institut Teknologi Sepuluh Nopember
                </p>
            </div>

            {/* ============ FKK LOGO ============ */}
            <div
                className="absolute inset-0 flex flex-col items-center justify-center transition-all duration-[1200ms]"
                style={{
                    opacity: isFKK ? 1 : 0,
                    transform: isFKK ? 'scale(1)' : phase === 'fkk_fade' ? 'scale(1.1)' : 'scale(0.9)',
                    pointerEvents: 'none',
                }}
            >
                <div className="relative">
                    <div
                        className="absolute inset-0 blur-3xl rounded-full"
                        style={{
                            background: 'radial-gradient(circle, rgba(99,102,241,0.3) 0%, transparent 70%)',
                            transform: 'scale(3)',
