                    </button>
                    <button
                        onClick={handleOrder}
                        disabled={lowStockMeds.length === 0}
                        className="px-6 py-2 bg-emerald-600 text-white rounded-lg font-semibold hover:bg-emerald-700 disabled:opacity-50"
                    >
                        <ShoppingCart className="inline mr-2" size={18} />
                        Kirim Order
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
