            satisfaction: referralResult.satisfaction
        };

        // Finalize discharge in context based on type
        if (isEmergency) {
            dischargeEmergencyPatient(patient, finalizeData);
        } else {
            dischargePatient(patient, finalizeData);
        }

        onClose();
    };

    const nextStep = () => setStep(s => s + 1);
