                                            </div>
                                        </div>
                                    );
                                }
                                return null;
                            })()}
                            <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100 flex gap-3 text-blue-800">
                                <Info size={20} className="shrink-0" />
                                <div className="text-xs leading-relaxed italic">
