            const med = getMedicationById(item.medicationId);
            if (!med) return null;
            return {
                id: item.medicationId,
                name: med.name,
                stock: item.stock,
                minStock: med.minStock,
                unit: med.type,
                category: med.category === MEDICATION_CATEGORIES.MEDICAL_EQUIPMENT ? 'alkes' :
                    med.category === MEDICATION_CATEGORIES.EMERGENCY ? 'igd' : 'obat',
                price: med.unitPrice,
                expiry: '2026-12', // Placeholder for simplicity
                icon: med.type === 'tablet' ? '💊' : med.type === 'botol' ? '🍯' : '💉'
            };
        }).filter(Boolean);
    }, [pharmacyInventory]);

    const handleRestock = (item) => {
        const cost = item.price * 100; // Buy 100 units
        if (stats.pendapatanUmum >= cost) {
            setStats(prev => ({ ...prev, pendapatanUmum: prev.pendapatanUmum - cost }));
            updateInventory(item.id, 100);
        } else {
            alert('Dana tidak cukup!');
        }
    };

    const filteredItems = (medicalInventory || [])
        .filter(item => {
            const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesCategory = filterCategory === 'all' || item.category === filterCategory;
            return matchesSearch && matchesCategory;
        })
        .sort((a, b) => {
            if (sortBy === 'stock') return a.stock - b.stock;
            if (sortBy === 'expiry') return new Date(a.expiry) - new Date(b.expiry);
            return a.name.localeCompare(b.name);
        });

    const lowStockCount = medicalInventory.filter(i => i.stock < i.minStock).length;
    const expiringCount = 0; // Simplified

    const totalItems = medicalInventory.reduce((sum, i) => sum + i.stock, 0);
    const totalValue = medicalInventory.reduce((sum, i) => sum + (i.stock * i.price), 0);

    // Theme-aware classes
    const bgMain = isDark
        ? 'bg-gradient-to-br from-slate-900 via-orange-900/30 to-amber-900/20'
        : 'bg-gradient-to-br from-orange-50 via-amber-50 to-yellow-50';
    const textPrimary = isDark ? 'text-white' : 'text-slate-800';
    const textSecondary = isDark ? 'text-orange-300' : 'text-orange-600';
    const cardBg = isDark ? 'bg-white/10 border-white/10' : 'bg-white border-orange-200 shadow-sm';
    const inputBg = isDark ? 'bg-white/10 border-white/10 text-white placeholder-slate-400' : 'bg-white border-orange-200 text-slate-800 placeholder-slate-400';
    const decorBg = isDark ? 'bg-orange-500/10' : 'bg-orange-200/50';

    return (
        <div className={`h-full overflow-auto ${bgMain}`}>
            {/* Decorative Elements */}
            <div className={`absolute top-0 right-0 w-96 h-96 ${decorBg} rounded-full blur-3xl pointer-events-none`} />
            <div className={`absolute bottom-0 left-0 w-64 h-64 ${decorBg} rounded-full blur-3xl pointer-events-none`} />

            <div className="relative z-10 p-6 max-w-7xl mx-auto">
                {/* Header */}
                <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center gap-4">
                        <div className="p-3 bg-gradient-to-br from-orange-500 to-amber-600 rounded-2xl shadow-lg shadow-orange-500/30">
                            <Package className="text-white" size={32} />
                        </div>
                        <div>
                            <h1 className={`text-3xl font-black tracking-tight ${textPrimary}`}>Sarana & Logistik</h1>
                            <p className={textSecondary}>Kelola stok obat, alkes, dan kebutuhan operasional</p>
                        </div>
                    </div>
                    <button className="bg-gradient-to-r from-orange-500 to-amber-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:shadow-lg hover:shadow-orange-500/30 hover:scale-[1.02] transition-all">
                        <ShoppingCart size={20} />
                        Pengadaan
                    </button>
                </div>

                {/* Stats Grid */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
                    <div className={`backdrop-blur-xl rounded-2xl p-5 border ${cardBg}`}>
                        <Box className="text-orange-500 mb-2" size={24} />
                        <div className={`text-2xl font-black ${textPrimary}`}>{totalItems.toLocaleString()}</div>
                        <div className={`text-sm ${textSecondary}`}>Total Item</div>
                    </div>
                    <div className={`backdrop-blur-xl rounded-2xl p-5 border ${cardBg}`}>
                        <BarChart3 className="text-green-500 mb-2" size={24} />
                        <div className={`text-2xl font-black ${textPrimary}`}>Rp {(totalValue / 1000000).toFixed(1)}M</div>
                        <div className={`text-sm ${isDark ? 'text-green-300' : 'text-green-600'}`}>Nilai Inventori</div>
                    </div>
                    <div className={`rounded-2xl p-5 border ${lowStockCount > 0 ? 'bg-red-500/20 border-red-500/30' : cardBg}`}>
                        <TrendingDown className={`mb-2 ${lowStockCount > 0 ? 'text-red-500' : 'text-slate-400'}`} size={24} />
                        <div className={`text-2xl font-black ${textPrimary}`}>{lowStockCount}</div>
                        <div className={`text-sm ${lowStockCount > 0 ? (isDark ? 'text-red-300' : 'text-red-600') : 'text-slate-400'}`}>Stok Rendah</div>
                    </div>
                    <div className={`rounded-2xl p-5 border ${expiringCount > 0 ? 'bg-amber-500/20 border-amber-500/30' : cardBg}`}>
                        <AlertTriangle className={`mb-2 ${expiringCount > 0 ? 'text-amber-500' : 'text-slate-400'}`} size={24} />
                        <div className={`text-2xl font-black ${textPrimary}`}>{expiringCount}</div>
                        <div className={`text-sm ${expiringCount > 0 ? (isDark ? 'text-amber-300' : 'text-amber-600') : 'text-slate-400'}`}>Segera Expired</div>
                    </div>
                </div>

                {/* Search & Filter Bar */}
                <div className={`backdrop-blur-xl rounded-2xl p-4 mb-6 flex flex-wrap gap-4 items-center border ${isDark ? 'bg-white/5 border-white/10' : 'bg-white/80 border-orange-200 shadow-sm'}`}>
                    <div className="flex-1 min-w-[200px] relative">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input
                            type="text"
                            placeholder="Cari barang..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className={`w-full pl-11 pr-4 py-3 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500/50 ${inputBg}`}
                        />
                    </div>
                    <div className="flex gap-2">
                        {['all', 'obat', 'alkes', 'apd'].map(cat => {
                            const Icon = cat !== 'all' ? CATEGORY_ICONS[cat] : Filter;
                            return (
                                <button
                                    key={cat}
                                    onClick={() => setFilterCategory(cat)}
                                    className={`px-4 py-2.5 rounded-xl font-bold flex items-center gap-2 transition-all ${filterCategory === cat
                                        ? cat === 'all' ? 'bg-slate-800 text-white' : `bg-gradient-to-r ${CATEGORY_COLORS[cat]} text-white shadow-lg`
                                        : isDark ? 'bg-white/10 text-slate-300 hover:bg-white/20' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                                        }`}
                                >
                                    <Icon size={16} />
                                    {cat === 'all' ? 'Semua' : cat.toUpperCase()}
                                    {cat !== 'all' && (
                                        <div
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                openWiki(`item_${cat}`);
                                            }}
                                            className="ml-1 p-0.5 hover:bg-white/20 rounded-full transition-colors"
                                        >
                                            <Info size={10} />
                                        </div>
                                    )}
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Inventory Cards */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    {filteredItems.map((item, idx) => {
                        const isLowStock = item.stock < item.minStock;
                        const isExpiring = (new Date(item.expiry) - new Date()) / (1000 * 60 * 60 * 24 * 30) < 3;

                        return (
                            <div
                                key={item.id}
                                className={`group backdrop-blur-sm rounded-2xl p-5 border transition-all duration-300 hover:scale-[1.02] cursor-pointer
                                    ${isDark ? 'bg-white/5 hover:bg-white/10' : 'bg-white hover:bg-orange-50 shadow-sm'}
                                    ${isLowStock ? 'border-red-500/50' : isExpiring ? 'border-amber-500/50' : isDark ? 'border-white/10' : 'border-orange-200'}
                                `}
                                style={{ animationDelay: `${idx * 30}ms` }}
                            >
                                <div className="flex items-start justify-between mb-4">
                                    <span className="text-3xl">{item.icon}</span>
                                    <span className={`text-xs font-bold px-2 py-1 rounded-full bg-gradient-to-r ${CATEGORY_COLORS[item.category]} text-white`}>
                                        {item.category.toUpperCase()}
                                    </span>
                                </div>

                                <h3 className={`font-bold mb-1 leading-tight ${textPrimary}`}>{item.name}</h3>

                                <div className="flex items-baseline gap-2 mb-3">
                                    <span className={`text-2xl font-black ${isLowStock ? 'text-red-500' : textPrimary}`}>
                                        {item.stock}
                                    </span>
                                    <span className={`text-sm ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>/ {item.minStock} {item.unit}</span>
                                </div>

                                <div className={`flex justify-between text-xs ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
                                    <span>Exp: {item.expiry}</span>
                                    <span>Rp {item.price.toLocaleString('id-ID')}</span>
                                </div>

                                {/* Stock Bar */}
                                <div className={`h-1.5 rounded-full mt-3 overflow-hidden ${isDark ? 'bg-white/10' : 'bg-slate-200'}`}>
                                    <div
                                        className={`h-full rounded-full transition-all ${isLowStock ? 'bg-red-500' : 'bg-gradient-to-r from-green-400 to-emerald-500'}`}
                                        style={{ width: `${Math.min(100, (item.stock / item.minStock) * 50)}%` }}
                                    />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

/**
 * @reflection
 * [IDENTITY]: SaveSlotSelector
 * [PURPOSE]: React UI component: MAX_SLOTS.
 * [STATE]: Experimental
 * [ANCHOR]: SaveSlotSelector
 * [DEPENDS_ON]: AvatarRenderer
 * [KNOWN_ISSUES]: None
 * [LAST_UPDATE]: 2026-02-12
 */

import React, { useState, useEffect, useRef } from 'react';
import { Trash2, Play, Plus, Clock, Calendar, Award, Download, Upload, CheckCircle, AlertCircle, ChevronDown, Dna } from 'lucide-react';
import AvatarRenderer from './AvatarRenderer.jsx';
import { getAssetUrl, ASSET_KEY } from '../assets/assets.js';

const MAX_SLOTS = 5;

export default function SaveSlotSelector({ onSelectSlot, onNewGame }) {
    const [slots, setSlots] = useState([]);
    const [confirmDelete, setConfirmDelete] = useState(null);
    const [notification, setNotification] = useState(null);
    const [showSlots, setShowSlots] = useState(false);
    const [titleAnimDone, setTitleAnimDone] = useState(false);

    // --- New State for Import Hardening ---
    const fileInputRef = useRef(null);
    const [importTargetSlot, setImportTargetSlot] = useState(null);
    const [overwriteTarget, setOverwriteTarget] = useState(null);
    const MAX_FILE_SIZE = 500 * 1024; // 500KB limit
    // --------------------------------------

    useEffect(() => { loadSlots(); }, []);

    // Title animation sequence
    useEffect(() => {
        const timer = setTimeout(() => setTitleAnimDone(true), 1800);
        return () => clearTimeout(timer);
    }, []);

    useEffect(() => {
        if (notification) {
            const timer = setTimeout(() => setNotification(null), 3000);
            return () => clearTimeout(timer);
        }
    }, [notification]);

    const loadSlots = () => {
        const loadedSlots = [];
        for (let i = 0; i < MAX_SLOTS; i++) {
            const key = `primer_save_${i}`;
            const data = localStorage.getItem(key);
            if (data) {
                try { loadedSlots.push({ slotId: i, ...JSON.parse(data) }); }
                catch { loadedSlots.push({ slotId: i, empty: true }); }
            } else {
                loadedSlots.push({ slotId: i, empty: true });
            }
        }
        setSlots(loadedSlots);
    };

    const handleDeleteSlot = (slotId) => {
        localStorage.removeItem(`primer_save_${slotId}`);
        loadSlots();
        setConfirmDelete(null);
        setNotification({ type: 'success', message: `Slot ${slotId + 1} berhasil dihapus` });
    };

    const formatDate = (timestamp) => {
        if (!timestamp) return '-';
        const d = new Date(timestamp);
        return d.toLocaleDateString('id-ID', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' });
    };

    const handleExportSave = (slotId) => {
        const key = `primer_save_${slotId}`;
        const data = localStorage.getItem(key);
        if (!data) { setNotification({ type: 'error', message: 'Tidak ada data untuk diekspor' }); return; }
        try {
            const parsed = JSON.parse(data);
            const exportData = { ...parsed, _exportInfo: { exportedAt: new Date().toISOString(), gameVersion: '1.0', originalSlot: slotId } };
            const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a'); a.href = url;
            a.download = `PRIMER_Save_${parsed.profile?.name || 'Unknown'}_Day${parsed.day || 1}_${new Date().toISOString().split('T')[0]}.json`;
            document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
            setNotification({ type: 'success', message: `Save berhasil diekspor!` });
        } catch { setNotification({ type: 'error', message: 'Gagal mengekspor save' }); }
    };

    const handleExportAll = () => {
        const allSaves = {}; let hasAnySave = false;
        for (let i = 0; i < MAX_SLOTS; i++) {
            const data = localStorage.getItem(`primer_save_${i}`);
            if (data) { try { allSaves[`slot_${i}`] = JSON.parse(data); hasAnySave = true; } catch { } }
        }
        if (!hasAnySave) { setNotification({ type: 'error', message: 'Tidak ada save untuk diekspor' }); return; }
        const blob = new Blob([JSON.stringify({ _exportInfo: { exportedAt: new Date().toISOString(), gameVersion: '1.0', type: 'all_saves' }, saves: allSaves }, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a'); a.href = url;
        a.download = `PRIMER_AllSaves_${new Date().toISOString().split('T')[0]}.json`;
        document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
        setNotification({ type: 'success', message: 'Semua save berhasil diekspor!' });
    };

    const handleImportClick = (slotId = null) => { setImportTargetSlot(slotId); fileInputRef.current?.click(); };

    // --- Hardened Import Logic ---

    const processImport = (slotId, data) => {
        try {
            localStorage.setItem(`primer_save_${slotId}`, JSON.stringify(data));
            loadSlots();
            setNotification({ type: 'success', message: `Save berhasil diimpor ke Slot ${slotId + 1}!` });
            setOverwriteTarget(null);
        } catch (e) {
            console.error('Import failed:', e);
            setNotification({ type: 'error', message: 'Gagal menyimpan data (Quota Exceeded?)' });
        }
    };

    const handleFileChange = (e) => {
        const file = e.target.files?.[0];
        if (!file) return;

        // 1. Size Validation
        if (file.size > MAX_FILE_SIZE) {
            setNotification({ type: 'error', message: `File terlalu besar (Max ${MAX_FILE_SIZE / 1024}KB)` });
            e.target.value = '';
            return;
        }

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const data = JSON.parse(event.target?.result);

                // 2. Structure Validation
                if (!data || typeof data !== 'object') throw new Error('Invalid JSON');

                // Check for 'all_saves' package
                if (data._exportInfo?.type === 'all_saves' && data.saves) {
                    let imported = 0;
                    Object.entries(data.saves).forEach(([slotKey, saveData]) => {
                        const match = slotKey.match(/slot_(\d+)/);
                        if (match) {
                            const slotId = parseInt(match[1]);
                            if (slotId >= 0 && slotId < MAX_SLOTS) {
                                // For bulk import, we currently skip confirmation (or it would be too spammy)
                                const { _exportInfo, ...cleanData } = saveData;
                                localStorage.setItem(`primer_save_${slotId}`, JSON.stringify(cleanData));
                                imported++;
                            }
                        }
                    });
                    loadSlots();
                    setNotification({ type: 'success', message: `${imported} save berhasil diimpor!` });
                } else {
                    // Single Save Import
                    const { _exportInfo, ...cleanData } = data;

                    // Validate essential fields
                    if (!cleanData.profile || !cleanData.stats) {
                        setNotification({ type: 'error', message: 'Format save file tidak valid (Missing profile/stats)' });
                        return;
                    }

                    const targetSlot = importTargetSlot !== null ? importTargetSlot : (_exportInfo?.originalSlot ?? 0);

                    if (targetSlot >= 0 && targetSlot < MAX_SLOTS) {
                        // Check if slot is occupied
                        const isOccupied = !slots.find(s => s.slotId === targetSlot)?.empty;

                        // 3. Overwrite Confirmation
                        if (isOccupied) {
                            setOverwriteTarget({ slotId: targetSlot, data: cleanData });
                        } else {
                            processImport(targetSlot, cleanData);
                        }
                    } else {
                        setNotification({ type: 'error', message: 'Slot tidak valid' });
                    }
                }
            } catch (err) {
                console.error(err);
                setNotification({ type: 'error', message: 'File rusak atau bukan JSON valid' });
            }
        };
        reader.readAsText(file);
        e.target.value = '';
    };

    const hasSaves = slots.some(s => !s.empty);

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-emerald-950 flex flex-col items-center justify-center relative overflow-hidden">
            {/* Hidden file input */}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />

            {/* Notification Toast */}
            {notification && (
                <div className={`fixed top-4 right-4 z-50 px-4 py-3 rounded-lg shadow-lg flex items-center gap-2
                    ${notification.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-red-500 text-white'}`}>
                    {notification.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
                    <span className="font-medium text-sm">{notification.message}</span>
                </div>
            )}

            {/* Overwrite Confirmation Modal */}
            {overwriteTarget && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-slate-900 border border-white/10 rounded-2xl p-6 max-w-md w-full shadow-2xl animate-in fade-in zoom-in duration-200">
                        <div className="flex items-center gap-3 text-amber-500 mb-4">
                            <AlertCircle size={32} />
                            <h3 className="text-lg font-bold">Konfirmasi Timpa Data</h3>
                        </div>
                        <p className="text-slate-300 text-sm mb-6">
                            Slot {overwriteTarget.slotId + 1} sudah berisi data. Apakah Anda yakin ingin menimpanya?
                            <br /><span className="text-red-400 text-xs mt-2 block">Data lama akan hilang permanen.</span>
                        </p>
                        <div className="flex justify-end gap-3">
                            <button
                                onClick={() => setOverwriteTarget(null)}
                                className="px-4 py-2 rounded-lg bg-white/5 text-white hover:bg-white/10 text-sm font-medium transition-colors"
                            >
                                Batal
                            </button>
                            <button
                                onClick={() => processImport(overwriteTarget.slotId, overwriteTarget.data)}
                                className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 text-sm font-bold shadow-lg shadow-red-900/20 transition-all hover:scale-105"
                            >
                                Ya, Timpa Data
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Animated Background Particles */}
            <div className="fixed inset-0 pointer-events-none overflow-hidden">
                {[...Array(20)].map((_, i) => (
                    <div key={i} className="absolute rounded-full"
                        style={{
                            width: 2 + Math.random() * 3,
                            height: 2 + Math.random() * 3,
                            left: `${Math.random() * 100}%`,
                            top: `${Math.random() * 100}%`,
                            background: `rgba(${i % 3 === 0 ? '16,185,129' : i % 3 === 1 ? '59,130,246' : '139,92,246'}, ${0.15 + Math.random() * 0.2})`,
                            animation: `float ${8 + Math.random() * 12}s ease-in-out infinite alternate`,
                            animationDelay: `${Math.random() * 5}s`,
                        }}
                    />
                ))}
            </div>

            {/* ========== TITLE SCREEN ========== */}
            <div className={`flex flex-col items-center transition-all duration-1000 ${showSlots ? 'mb-4' : 'mb-0'}`}>
                {/* Logo with Stethoscope */}
                <div className={`transition-all duration-1000 ${titleAnimDone ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-8'}`}>
                    <div className="flex justify-center mb-4">
                        <div className="bg-emerald-500/15 p-4 rounded-2xl border border-emerald-500/20 shadow-lg shadow-emerald-900/30">
                            <Dna size={44} className="text-emerald-400" />
                        </div>
                    </div>
                </div>

                {/* PRIMER Logo — SVG custom font for trademark consistency */}
                <div className={`transition-all duration-700 delay-300 ${titleAnimDone ? 'opacity-100 scale-100' : 'opacity-0 scale-95'}`}>
                    <h1 className="text-center select-none">
                        <span className="text-5xl md:text-6xl font-black tracking-[0.2em] text-transparent bg-clip-text bg-gradient-to-r from-white via-emerald-200 to-white"
                            style={{
                                fontFamily: "'Audiowide', 'Orbitron', 'Rajdhani', sans-serif",
                                textShadow: '0 0 40px rgba(16,185,129,0.3)',
                                WebkitTextStroke: '0.5px rgba(255,255,255,0.1)',
                            }}>
                            PRIMER
                        </span>
                    </h1>
                    <p className="text-center text-emerald-300/60 text-xs uppercase tracking-[0.3em] mt-2 font-medium">
                        Primary Care Manager Simulator
                    </p>
                </div>

                {/* Tagline */}
                <div className={`mt-6 transition-all duration-700 delay-700 ${titleAnimDone ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
                    <p className="text-white/40 text-sm italic text-center max-w-md px-4">
                        "Bridging clinical excellence and public health leadership."
                    </p>
                </div>

                {/* Action Buttons - Game Style */}
                <div className={`mt-8 flex flex-col items-center gap-3 transition-all duration-700 delay-1000 ${titleAnimDone ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}`}>
                    {!showSlots ? (
                        <>
                            <button
                                onClick={() => setShowSlots(true)}
                                className="group relative px-10 py-4 bg-gradient-to-r from-emerald-600 to-teal-600 text-white font-bold text-lg rounded-xl shadow-lg shadow-emerald-900/50 hover:shadow-emerald-700/50 hover:from-emerald-500 hover:to-teal-500 transition-all hover:scale-105 active:scale-95"
                            >
                                <span className="relative z-10 flex items-center gap-2">
                                    <Play size={22} /> {hasSaves ? 'Lanjutkan Permainan' : 'Mulai Permainan'}
                                </span>
                                <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-emerald-400 to-teal-400 opacity-0 group-hover:opacity-20 transition-opacity" />
                            </button>

                            {hasSaves && (
                                <button
                                    onClick={() => {
                                        const emptySlot = slots.find(s => s.empty);
                                        if (emptySlot) onNewGame(emptySlot.slotId);
                                        else setNotification({ type: 'error', message: 'Semua slot penuh. Hapus salah satu terlebih dahulu.' });
                                    }}
                                    className="px-6 py-2.5 text-white/50 hover:text-white border border-white/10 hover:border-white/25 rounded-lg text-sm transition-all hover:bg-white/5"
                                >
                                    <Plus size={16} className="inline mr-1" /> Game Baru
