/**
 * @reflection
 * [IDENTITY]: WilayahPage
 * [PURPOSE]: React UI component: WilayahPage.
 * [STATE]: Experimental
 * [ANCHOR]: WilayahPage
 * [DEPENDS_ON]: GameContext, EducationalWikiModal, OutbreakModal, PosyanduModal, WikiData, VillageRegistry, TextureGenerator, wilayah modular components
 * [KNOWN_ISSUES]: None
 * [LAST_UPDATE]: 2026-02-12
 */

import React, { useEffect, useRef, useState, useMemo, useCallback } from 'react';
import ErrorBoundary from './ErrorBoundary.jsx';
import { useGame } from '../context/GameContext.jsx';
import {
    Map, Home as HomeIcon, Users, User, AlertTriangle, Activity, ChevronRight,
    Footprints, TreePine, Mountain, Waves, Store, Building, Castle,
    Layers, BarChart3, Stethoscope, Droplets, Thermometer, Search,
    Folder, X, ClipboardCheck, Bug, BookOpen, Calendar, Info,
    Plus, Minus, Minimize, Check, Clock, Baby, Accessibility,
    Pill, Heart, GraduationCap, Utensils, Pickaxe, Megaphone
} from 'lucide-react';

import EducationalWikiModal from './EducationalWikiModal.jsx';
import OutbreakModal from './OutbreakModal.jsx';
import PosyanduModal from './PosyanduModal.jsx';
import { WIKI_DATA } from '../data/WikiData.js';

// Modular Imports
import {
    TILE_TYPES,
    BUILDING_TYPES,
    AI_ASSETS,
    PISPK_INDICATORS,
    HOME_VISIT_INTERVENTIONS,
    INTERVENTION_EDUCATION
} from './wilayah/constants.js';
import { generateVillageMap, getWikiKeyForBuilding } from './wilayah/map-utils.js';
import TerrainCanvas from './wilayah/TerrainCanvas.jsx';
import MapCanvas from './wilayah/MapCanvas.jsx';
import {
    ImageMapCanvas,
    PISPKPanel,
    VillageProfile,
    IKSBoardPanel
} from './wilayah/AuxiliaryComponents.jsx';

import { getCachedTextures, generateTextures } from '../utils/TextureGenerator.js';

export default function WilayahPage() {
    const {
        day, time, setGameState, villageData, setVillageData,
        viewParams, navigate, history, playerStats, setPlayerStats,
        addXp, checkQuestProgress, setReputation, reputation,
        soundManager, activeOutbreaks, outbreakNotification,
        setOutbreakNotification, triggerOutbreak, OUTBREAK_TYPES,
        openWiki, isWikiOpen, closeWiki, updateProgress, wikiMetric
    } = useGame();

    // Fix NaN energy bar: Ensure values are cast correctly
    const energy = Math.max(0, Math.floor(Number(playerStats?.energy) || 0));

    const [selectedBuilding, setSelectedBuilding] = useState(null);
    const [viewMode, setViewMode] = useState('map'); // 'map', 'satelite', or 'profile'
    const [activeLayer, setActiveLayer] = useState('general'); // 'general', 'pispk', 'surveillance', 'psn'
    const [peModal, setPeModal] = useState(null);
    const [homeVisitModal, setHomeVisitModal] = useState(null);
    const [showRiskOnly, setShowRiskOnly] = useState(false);
    const [textures, setTextures] = useState(() => getCachedTextures('v10-modular-refactor'));
    const [isAnnouncementOpen, setIsAnnouncementOpen] = useState(false);
    const [isOutbreakModalOpen, setIsOutbreakModalOpen] = useState(false);
    const [showPosyanduModal, setShowPosyanduModal] = useState(false);
    const [peChecklist, setPeChecklist] = useState({ bakMandi: false, barangBekas: false });
    const [familySearch, setFamilySearch] = useState('');

    useEffect(() => {
        if (!textures) {
            const tex = generateTextures('v10-modular-refactor');
            setTextures(tex);
        }
    }, [textures]);


    const mapData = useMemo(() => generateVillageMap(60, 50, 42, villageData), [villageData]);

    const [zoom, setZoom] = useState(0.4);
    const viewportRef = useRef(null);

    const scrollToBuilding = useCallback((building) => {
        if (!viewportRef.current || !building) return;
        const container = viewportRef.current;
        const TILE_SIZE = 36;
        const paddingX = container.clientWidth * 0.15;
        const paddingY = container.clientHeight * 0.15;
        const targetX = (paddingX + building.x * TILE_SIZE + 1.5 * TILE_SIZE) * zoom;
        const targetY = (paddingY + building.y * TILE_SIZE + 1.5 * TILE_SIZE) * zoom;
        container.scrollTo({
            left: targetX - container.clientWidth / 2,
            top: targetY - container.clientHeight / 2,
            behavior: 'smooth'
        });
    }, [zoom]);

    useEffect(() => {
        if (viewParams && viewParams.focusHouseId && mapData) {
            const target = mapData.buildings.find(b => b.id === viewParams.focusHouseId || b.familyId === viewParams.focusHouseId);
            if (target) {
                setViewMode('map');
                setSelectedBuilding(target);
                setTimeout(() => scrollToBuilding(target), 300);
            }
        }
    }, [viewParams, mapData, scrollToBuilding]);

    const surveillanceStatus = useMemo(() => {
        const status = {};
        if (!villageData || !history) return status;
        const recentHistory = history.filter(p => (day - p.day) <= 14);
        recentHistory.forEach(p => {
            if (!p.medicalData || !p.medicalData.diagnosisCode) return;
            const dx = p.medicalData.diagnosisCode;
            const houseId = p.hidden?.familyId ? villageData.families.find(f => f.id === p.hidden.familyId)?.houseId : null;
            if (houseId) {
                let caseType = null;
                if (dx.startsWith('A90') || dx.startsWith('A91')) caseType = 'dbd';
                else if (dx.startsWith('B5')) caseType = 'malaria';
                else if (dx.startsWith('A0')) caseType = 'diare';
                else if (dx.startsWith('J1')) caseType = 'pneumonia';
                if (caseType) {
                    status[houseId] = {
                        hasCase: true,
                        caseType: caseType,
                        patientName: p.name,
                        diagnosis: p.medicalData.diagnosisName,
                        date: p.day
                    };
                }
            }
        });
        return status;
    }, [history, day, villageData]);

    const centerMap = useCallback(() => {
        if (viewportRef.current && mapData) {
            const container = viewportRef.current;
            const TILE_SIZE = 36;
            const vw = container.clientWidth;
            const vh = container.clientHeight;
            const paddingX = vw * 0.15;
            const paddingY = vh * 0.15;
            const midX = mapData.width / 2;
            const midY = mapData.height / 2;
            const targetX = (paddingX + midX * TILE_SIZE) * zoom;
            const targetY = (paddingY + midY * TILE_SIZE) * zoom;
            container.scrollTo({
                left: targetX - vw / 2,
                top: targetY - vh / 2,
                behavior: 'smooth'
            });
        }
    }, [mapData, zoom]);

    useEffect(() => {
        const handleKeyDown = (e) => {
            if (e.key === '+' || e.key === '=') {
                setZoom(prev => Math.min(prev + 0.1, 1.5));
                e.preventDefault();
            } else if (e.key === '-' || e.key === '_') {
                setZoom(prev => Math.max(prev - 0.1, 0.2));
                e.preventDefault();
            } else if (e.key === '0') {
                setZoom(0.4);
                centerMap();
                e.preventDefault();
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [centerMap]);

    if (!textures) return <div className="p-10 text-center">Loading High-Res Textures...</div>;

    const stats = {
        totalHouses: villageData?.families?.length || 0,
        avgIks: villageData?.families?.reduce((acc, f) => {
            const ind = f.indicators || {};
            const scored = Object.values(ind).filter(v => v !== null).length;
            const healthy = Object.values(ind).filter(v => v === true).length;
            return acc + (scored > 0 ? healthy / scored : 0);
        }, 0) / (villageData?.families?.length || 1),
        alertCount: Object.keys(surveillanceStatus).length
    };

    const handleHomeVisitAction = (action) => {
        if (energy < action.energy) return;
        const family = villageData.families.find(f => f.id === selectedBuilding.familyId);
        if (!family) return;
        let updatedIndicators = { ...family.indicators };
        const idToUpdate = action.indicator || action.indicators?.[0];
        if (idToUpdate) updatedIndicators[idToUpdate] = true;
        setVillageData(prev => ({
            ...prev,
            families: prev.families.map(f => f.id === family.id ? { ...f, indicators: updatedIndicators } : f)
        }));
        setPlayerStats(prev => ({ ...prev, energy: energy - action.energy }));
        addXp(action.xp);

        // Update Quest/Story Progress
        if (updateProgress) {
            updateProgress('home_visits', 1);
            if (action.id === 'psn') {
                updateProgress('psn_done', 1);
            }
        }

        navigate('megalog', { type: 'home_visit', familyId: family.id, action: action.id });
    };

    return (
        <ErrorBoundary>
            <div className="flex flex-col h-screen bg-slate-50 overflow-hidden font-sans">
                {/* Header Section */}
                <div className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm z-30">
                    <div className="flex items-center gap-6">
                        <button
                            onClick={() => navigate('dashboard')}
                            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
                        >
                            <X size={20} className="text-slate-400" />
                        </button>
                        <div>
                            <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                                <Map className="text-emerald-500" size={24} />
                                Wilayah Kerja Puskesmas
                            </h2>
                            <p className="text-xs text-slate-500 font-medium">Pemantauan Terpadu Desa Sukamaju • RW 01-05</p>
                        </div>
                    </div>

                    {/* View Switchers */}
                    <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
                        <button
                            onClick={() => setViewMode('map')}
                            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-800'}`}
                        >
                            <Layers size={14} /> PETA DESA
                        </button>
                        <button
                            onClick={() => setViewMode('satelite')}
                            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'satelite' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-800'}`}
                        >
                            <Waves size={14} /> SATELIT
                        </button>
                        <button
                            onClick={() => setViewMode('profile')}
                            className={`px-4 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${viewMode === 'profile' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-800'}`}
                        >
                            <HomeIcon size={14} /> PROFIL DESA
                        </button>
                    </div>

                </div>

                <div className="relative flex-1 flex overflow-hidden">
                    {/* Main Content Area */}
                    <div className="relative flex-1 bg-[#d1e8c4] overflow-hidden">
                        {viewMode === 'profile' ? (
                            <div className="absolute inset-0 overflow-y-auto p-12 bg-slate-50/50">
                                <VillageProfile />
                            </div>
                        ) : (
                            <div
                                ref={viewportRef}
                                className="absolute inset-0 overflow-auto cursor-grab active:cursor-grabbing scrollbar-hide select-none"
                                onMouseDown={(e) => {
                                    if (e.button !== 0) return;
                                    const startX = e.pageX - viewportRef.current.offsetLeft;
                                    const startY = e.pageY - viewportRef.current.offsetTop;
                                    const scrollLeft = viewportRef.current.scrollLeft;
                                    const scrollTop = viewportRef.current.scrollTop;
                                    const onMouseMove = (moveEvent) => {
                                        const x = moveEvent.pageX - viewportRef.current.offsetLeft;
                                        const y = moveEvent.pageY - viewportRef.current.offsetTop;
                                        const walkX = (x - startX);
                                        const walkY = (y - startY);
                                        viewportRef.current.scrollLeft = scrollLeft - walkX;
                                        viewportRef.current.scrollTop = scrollTop - walkY;
                                    };
                                    const onMouseUp = () => {
                                        window.removeEventListener('mousemove', onMouseMove);
                                        window.removeEventListener('mouseup', onMouseUp);
                                    };
                                    window.addEventListener('mousemove', onMouseMove);
                                    window.addEventListener('mouseup', onMouseUp);
                                }}
                            >
                                <div
                                    className="relative origin-top-left"
                                    style={{
                                        width: `${mapData.width * 36 + 2000}px`,
                                        height: `${mapData.height * 36 + 2000}px`,
                                        transform: `scale(${zoom})`,
                                        padding: '1000px'
                                    }}
                                >
                                    {viewMode === 'map' ? (
                                        <>
                                            <MapCanvas
                                                mapData={mapData}
                                                selectedBuilding={selectedBuilding}
                                                onSelectBuilding={setSelectedBuilding}
                                                textures={textures}
                                                TILE_SIZE={36}
                                                activeLayer={activeLayer}
                                                surveillanceStatus={surveillanceStatus}
                                                showRiskOnly={showRiskOnly}
                                            />
                                        </>
                                    ) : (
                                        <ImageMapCanvas
                                            mapData={mapData}
                                            selectedBuilding={selectedBuilding}
                                            onSelectBuilding={setSelectedBuilding}
                                        />
                                    )}
                                </div>

                                {/* Zoom Controls (Corner) */}
                                <div className="fixed bottom-12 left-6 flex flex-col gap-2 z-50 pointer-events-auto">
                                    <button onClick={() => setZoom(prev => Math.min(prev + 0.1, 1.5))} className="w-10 h-10 bg-white border border-slate-200 rounded-xl shadow-lg flex items-center justify-center text-slate-600 hover:text-indigo-600 transition-colors"><Plus size={18} /></button>
                                    <button onClick={() => setZoom(prev => Math.max(prev - 0.1, 0.2))} className="w-10 h-10 bg-white border border-slate-200 rounded-xl shadow-lg flex items-center justify-center text-slate-600 hover:text-indigo-600 transition-colors"><Minus size={18} /></button>
                                    <button onClick={() => { setZoom(0.4); centerMap(); }} className="w-10 h-10 bg-white border border-slate-200 rounded-xl shadow-lg flex items-center justify-center text-slate-600 hover:text-indigo-600 transition-colors"><Minimize size={18} /></button>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Sidebar Area */}
                    <div className="w-[450px] bg-white border-l border-slate-200 flex flex-col z-20 shadow-2xl">
                        {selectedBuilding ? (
                            <div className="flex-1 flex flex-col animate-in slide-in-from-right duration-300">
                                {/* Detail Header */}
                                <div className="p-8 border-b border-slate-100 relative overflow-hidden group">
                                    <div className="absolute top-0 right-0 p-8">
                                        <button
                                            onClick={() => setSelectedBuilding(null)}
                                            className="p-2 bg-slate-100 hover:bg-slate-200 rounded-full transition-colors text-slate-500"
                                        >
                                            <X size={20} />
                                        </button>
                                    </div>

                                    <div className="flex items-center gap-3 mb-4">
                                        <span className="px-3 py-1 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase tracking-widest rounded-full border border-indigo-100">
                                            {selectedBuilding.type?.replace(/_/g, ' ')}
                                        </span>
                                        {selectedBuilding.familyId && (
                                            <span className="px-3 py-1 bg-emerald-50 text-emerald-600 text-[10px] font-black uppercase tracking-widest rounded-full border border-emerald-100">
                                                Hunian Aktif
                                            </span>
                                        )}
                                    </div>

                                    <h3 className="text-3xl font-black text-slate-900 leading-tight mb-2 tracking-tighter">
                                        {selectedBuilding.name}
                                    </h3>

                                    <div className="flex items-center gap-4 text-xs font-bold text-slate-400">
                                        <div className="flex items-center gap-1.5">
                                            <Map size={14} /> Koordinat: {selectedBuilding.x}, {selectedBuilding.y}
                                        </div>
                                        {selectedBuilding.familyId && (
                                            <div className="flex items-center gap-1.5">
                                                <HomeIcon size={14} /> RW 0{Math.floor(selectedBuilding.x / 12) + 1}
                                            </div>
                                        )}
                                    </div>

                                    {/* Building Sprite View */}
                                    <div className="mt-8 aspect-video bg-gradient-to-br from-indigo-50/50 to-emerald-50/50 rounded-3xl border-2 border-slate-100 flex items-center justify-center group-hover:scale-[1.02] transition-transform duration-500 relative overflow-hidden">
                                        <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'radial-gradient(#6366f1 0.5px, transparent 0.5px)', backgroundSize: '24px 24px' }} />
                                        <img
                                            // Standardize key access: house_red -> textures.house_red
                                            src={textures?.[selectedBuilding.type] || textures?.[`inset_${selectedBuilding.type.split('_')[0]}`] || AI_ASSETS[selectedBuilding.type.toUpperCase()] || AI_ASSETS.HOUSE_MODERN}
                                            alt={selectedBuilding.type}
                                            className="w-48 h-48 object-contain drop-shadow-2xl relative z-10 filter"
                                            style={{ imageRendering: 'pixelated' }}
                                        />
                                    </div>
                                </div>

                                <div className="flex-1 overflow-y-auto p-8 scrollbar-hide">
                                    {selectedBuilding.familyId ? (
                                        <PISPKPanel
                                            building={selectedBuilding}
                                            villageData={villageData}
                                            onOpenWiki={openWiki}
                                            onOpenIntervention={() => setHomeVisitModal(selectedBuilding)}
                                        />
                                    ) : (
                                        <div className="space-y-6">
                                            <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                                                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Informasi Publik</h4>
                                                <p className="text-sm font-medium text-slate-600 leading-relaxed mb-6">
                                                    {selectedBuilding.description || `${selectedBuilding.name} merupakan sarana umum penting di Desa Sukamaju yang melayani kebutuhan dasar warga.`}
                                                </p>

                                                {selectedBuilding.type === BUILDING_TYPES.IKS_SCOREBOARD && (
                                                    <div data-testid="wilayah-iks-board">
                                                        <IKSBoardPanel
                                                            stats={stats}
                                                            onOpenAnnouncements={() => setIsAnnouncementOpen(true)}
                                                        />
                                                    </div>
                                                )}
                                            </div>

                                            <button
                                                onClick={() => openWiki(getWikiKeyForBuilding(selectedBuilding.type))}
                                                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white p-5 rounded-2xl font-black text-sm flex items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-[0.98] shadow-xl shadow-indigo-600/20"
                                            >
                                                <BookOpen size={20} /> LIHAT WIKI & PROSEDUR
                                            </button>
                                        </div>
                                    )}
                                </div>

                                {selectedBuilding.familyId && (
                                    <div className="p-8 bg-slate-50 border-t border-slate-200">
                                        <button
                                            onClick={() => setHomeVisitModal(selectedBuilding)}
                                            className="w-full bg-slate-900 hover:bg-black text-white p-5 rounded-2xl font-black text-sm flex items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-[0.98] shadow-xl shadow-slate-900/20"
                                        >
                                            <Footprints size={20} /> LAKUKAN KUNJUNGAN RUMAH
                                        </button>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center p-12 text-center">
                                <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center mb-8 text-slate-300">
                                    <Search size={48} />
                                </div>
                                <h3 className="text-xl font-black text-slate-900 mb-2 tracking-tight">Pilih Titik di Peta</h3>
                                <p className="text-slate-500 text-sm font-medium max-w-[280px]">Klik pada rumah atau bangunan untuk melihat detail PIS-PK dan informasi kesehatan wilayah.</p>

                                <div className="mt-12 grid grid-cols-2 gap-4 w-full">
                                    <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 text-left">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total RW</p>
                                        <p className="text-xl font-black text-slate-800">05</p>
                                    </div>
                                    <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 text-left">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Target KK</p>
                                        <p className="text-xl font-black text-slate-800">{villageData?.families?.length || 0}</p>
                                    </div>
                                </div>

                                {/* Overlay Controls (Sidebar Version) */}
                                <div className="mt-8 border-t border-slate-100 pt-8 w-full text-left">
                                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Overlay Wilayah</h4>
                                    <div className="grid grid-cols-2 gap-2">
                                        {[
                                            { id: 'general', label: 'Infrastruktur', icon: Building },
                                            { id: 'pispk', label: 'PIS-PK', icon: HomeIcon },
                                            { id: 'surveillance', label: 'Surveilans', icon: Activity },
                                            { id: 'psn', label: 'Jentik', icon: Bug }
                                        ].map(layer => (
                                            <button
                                                key={layer.id}
                                                onClick={() => setActiveLayer(layer.id)}
                                                className={`flex items-center gap-2 px-3 py-2.5 rounded-xl text-[10px] font-black transition-all ${activeLayer === layer.id ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}
                                            >
                                                <layer.icon size={12} /> {layer.label.toUpperCase()}
                                            </button>
                                        ))}
                                    </div>

                                    {activeLayer === 'pispk' && (
                                        <div className="mt-4 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in slide-in-from-top-2 duration-300">
                                            <div className="space-y-3">
                                                <label className="flex items-center gap-2 cursor-pointer group">
                                                    <input
                                                        type="checkbox"
                                                        checked={showRiskOnly}
                                                        onChange={() => setShowRiskOnly(!showRiskOnly)}
                                                        className="hidden"
                                                    />
                                                    <div className={`w-4 h-4 rounded border transition-colors ${showRiskOnly ? 'bg-indigo-600 border-indigo-600' : 'border-slate-300'}`}>
                                                        {showRiskOnly && <Check size={12} className="text-white" />}
                                                    </div>
                                                    <span className="text-[10px] font-black text-slate-700 group-hover:text-indigo-600 uppercase">Filter Risiko</span>
                                                </label>
                                                <div className="pt-2 border-t border-indigo-100/50">
                                                    <div className="flex items-center justify-between text-[9px] font-bold"><span className="text-slate-500">Sehat</span><span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span></div>
                                                    <div className="flex items-center justify-between text-[9px] font-bold"><span className="text-slate-500">Waspada</span><span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span></div>
                                                    <div className="flex items-center justify-between text-[9px] font-bold"><span className="text-slate-500">Risiko</span><span className="w-1.5 h-1.5 rounded-full bg-rose-500"></span></div>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* MODALS */}
                {homeVisitModal && (
                    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-6 bg-slate-900/40 backdrop-blur-md animate-in fade-in duration-300">
                        <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in slide-in-from-bottom-8 duration-500">
                            <div className="bg-slate-900 text-white p-8">
                                <div className="flex justify-between items-start mb-6">
                                    <div className="flex items-center gap-3">
                                        <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center">
                                            <Footprints size={24} />
                                        </div>
                                        <div>
                                            <h3 className="text-2xl font-black tracking-tighter">Kunjungan Rumah (PIS-PK)</h3>
                                            <p className="text-xs text-white/50 font-bold uppercase tracking-wider">{homeVisitModal.name}</p>
                                        </div>
                                    </div>
                                    <button onClick={() => setHomeVisitModal(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                                        <X size={20} />
                                    </button>
                                </div>
                                <div className="grid grid-cols-2 gap-6 p-4 bg-white/5 rounded-2xl border border-white/10">
                                    <div className="flex flex-col">
                                        <span className="text-[10px] font-black text-white/40 uppercase tracking-widest">Energi Tersedia</span>
                                        <span className="text-lg font-black text-amber-400">{energy} EP</span>
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-[10px] font-black text-white/40 uppercase tracking-widest">Status IKS</span>
                                        <span className="text-lg font-black text-emerald-400">PRA SEHAT</span>
                                    </div>
                                </div>
                            </div>

                            <div className="p-8 max-h-[500px] overflow-y-auto scrollbar-hide">
                                <div className="grid grid-cols-1 gap-3">
                                    {HOME_VISIT_INTERVENTIONS.map((action) => {
                                        const isCompleted = homeVisitModal.familyId && villageData.families.find(f => f.id === homeVisitModal.familyId)?.indicators?.[action.indicator];
                                        return (
                                            <button
                                                key={action.id}
                                                disabled={energy < action.energy || isCompleted}
                                                onClick={() => handleHomeVisitAction(action)}
                                                className={`flex items-center gap-4 p-4 rounded-2xl border-2 transition-all text-left ${isCompleted ? 'bg-emerald-50 border-emerald-100 opacity-60' : energy >= action.energy ? 'bg-white border-slate-100 hover:border-indigo-500 hover:shadow-lg' : 'bg-slate-50 border-slate-100 opacity-50 cursor-not-allowed'}`}
                                            >
                                                <div className="text-2xl">{action.icon}</div>
                                                <div className="flex-1">
                                                    <h4 className="font-black text-slate-900 text-sm uppercase tracking-tight">{action.label}</h4>
                                                    <p className="text-xs text-slate-500 font-medium">{action.description}</p>
                                                </div>
                                                <div className="text-right">
                                                    {isCompleted ? (
                                                        <span className="text-[10px] font-black text-emerald-600 bg-emerald-100 px-2 py-1 rounded-lg uppercase">Selesai</span>
                                                    ) : (
                                                        <div className="flex flex-col items-end">
                                                            <span className="text-xs font-black text-amber-600">-{action.energy} EP</span>
                                                            <span className="text-[10px] font-black text-indigo-600 uppercase">+{action.xp} XP</span>
                                                        </div>
                                                    )}
                                                </div>
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                <EducationalWikiModal
                    isOpen={isWikiOpen}
                    onClose={closeWiki}
                    initialTab={wikiMetric}
                />
            </div>
        </ErrorBoundary>
    );
}

