                    <ArrowLeft size={18} />
                </button>
                <div>
                    <h2 className="text-xl font-black text-white/90 uppercase tracking-tight flex items-center gap-2" style={{ fontFamily: "'Audiowide', sans-serif" }}>
                        <Shield size={20} className="text-amber-400" />
                        Accreditation Command
                    </h2>
                    <p className="text-amber-300/50 text-[10px] uppercase tracking-[0.3em] mt-0.5 ml-7 font-medium">5 Bab • Radar • Standar Nasional</p>
                </div>
            </div>

