                                <span className={`text-[10px] font-black uppercase tracking-wider ${isDark ? 'text-amber-400' : 'text-amber-700'}`}>
                                    {maiaAlerts[0].priority === 'high' ? '🔴' : maiaAlerts[0].priority === 'medium' ? '🟡' : '🔵'} MAIA Suggestion
                                </span>
                                <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded ${isDark ? 'bg-amber-500/20 text-amber-300' : 'bg-amber-100 text-amber-700'}`}>
                                    Click to go to {maiaAlerts[0].suggestTab?.toUpperCase()}
                                </span>
                            </div>
                            <p className={`text-xs font-bold mt-1 leading-tight ${isDark ? 'text-amber-200' : 'text-amber-900'}`}>
                                {maiaAlerts[0].message}
