                                            <span className={`text-[8px] font-bold ${selectedProcedures.some(x => (x.id || x.code) === proc.id || (x.id || x.code) === proc.code) ? 'text-blue-300' : 'text-slate-400'}`}>Rp {proc.cost.toLocaleString('id-ID')}</span>
