export default function SOAPResume({
    patient,
    isDark,
    caseData,
    anamnesisHistory = [],
    examsPerformed = {},
    labsRevealed = {},
    selectedDiagnoses = [],
    selectedMeds = [],
    selectedProcedures = [],
    selectedEducation = []
}) {
    const examKeys = Array.isArray(examsPerformed) ? examsPerformed : Object.keys(examsPerformed || {});
