                                                </p>
                                            ))}
                                        </div>
                                    ))}
                                    {synthesis.unaskedEssentials.length > 0 && (
                                        <p className="text-rose-400 text-[10px] mt-1">⚠ Belum ditanyakan: {synthesis.unaskedEssentials.map(e => e.label).join(', ')}</p>
