                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* P: Planning */}
            <div>
                <h4 className={`text-[10px] font-black uppercase tracking-widest mb-1.5 ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>
