// PIS-PK Detail Panel
export const PISPKPanel = ({ building, villageData, onOpenIntervention, onOpenWiki }) => {
    const { navigate } = useGame();

    // Find Family Data (Fresh from villageData) to ensure reactive updates
    const family = villageData?.families?.find(f => f.id === building.familyId);

    // Use fresh indicators from family if available, otherwise fallback to building prop
    const indicators = family?.indicators || building.indicators || {};

    // Calculate IKS Score on the fly
    const scoredIndicators = Object.values(indicators).filter(v => v !== null).length;
    const healthyIndicators = Object.values(indicators).filter(v => v === true).length;
    const score = scoredIndicators > 0 ? healthyIndicators / scoredIndicators : 0;

    return (
        <div className="space-y-4">
            <div
                onClick={() => onOpenWiki('iks')}
                className="bg-slate-100 dark:bg-slate-800/50 p-4 rounded-lg cursor-pointer hover:bg-indigo-50 dark:hover:bg-indigo-900/30 transition-all group border border-transparent hover:border-indigo-200 dark:hover:border-indigo-500/50"
            >
                <div className="flex justify-between items-center mb-2">
                    <div className="flex items-center gap-2">
                        <span className="font-bold text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider">Skor IKS Keluarga</span>
                        <Info size={14} className="text-slate-300 dark:text-slate-600 group-hover:text-indigo-400 transition-colors" />
                    </div>
                    <span className={`px-2 py-0.5 rounded-full text-xs font-bold
                        ${score > 0.8 ? 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-400' :
                            score > 0.5 ? 'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-400' :
                                'bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-400'}
                    `}>
                        {(score * 100).toFixed(0)}%
                    </span>
                </div>
                <div className="w-full bg-slate-200 dark:bg-slate-700 h-2 rounded-full overflow-hidden">
                    <div
                        className={`h-full transition-all duration-500 ${score > 0.8 ? 'bg-green-500' : score > 0.5 ? 'bg-amber-500' : 'bg-red-500'}`}
                        style={{ width: `${score * 100}%` }}
                    />
                </div>
                <p className="text-[10px] uppercase font-bold text-slate-400 dark:text-slate-500 mt-2 text-right tracking-tight">
                    {score > 0.8 ? 'Keluarga Sehat' : score > 0.5 ? 'Pra-Sehat' : 'Tidak Sehat'}
                </p>
            </div>

            {/* Family Members List */}
            {family && family.members && (
                <div className="bg-white/5 border border-white/5 rounded-2xl p-4">
                    <h4 className="font-black text-[10px] text-white/30 uppercase mb-4 flex items-center gap-1.5 tracking-widest">
                        <Users size={12} /> Anggota Keluarga ({family.members.length})
                    </h4>
                    <div className="space-y-2">
                        {family.members.map((m, i) => {
                            const profile = INDIVIDUAL_PROFILES?.[m.id];
                            const hasConditions = (profile?.conditions?.length > 0) || (m.riskFactors?.length > 0);
                            const getWikiKey = () => {
                                if (profile?.conditions?.length > 0) {
                                    const c = profile.conditions[0];
                                    if (c.includes('hypertension')) return 'hypertension';
                                    if (c.includes('diabetes')) return 'diabetes';
                                    if (c.includes('stunting')) return 'stunting';
                                    if (c.includes('tb')) return 'tbc';
                                }
                                if (m.riskFactors?.includes('stunting')) return 'stunting';
                                if (m.riskFactors?.includes('hypertension_risk')) return 'hypertension';
                                if (m.riskFactors?.includes('tb_contact')) return 'tbc';
                                if (m.riskFactors?.includes('poor_sanitation')) return 'mck';
                                return 'iks';
                            };

                            return (
                                <div
                                    key={i}
                                    className={`w-full group/member flex flex-col gap-2 p-3 rounded-xl border transition-all
                                        ${hasConditions
                                            ? 'bg-amber-500/10 border-amber-500/30'
                                            : 'bg-white/5 border-white/5'
                                        }`}
                                >
                                    <div className="flex items-center gap-3">
                                        <button
                                            onClick={() => onOpenWiki(getWikiKey())}
                                            className={`w-10 h-10 rounded-full flex items-center justify-center text-sm shadow-inner shrink-0 transition-all active:scale-90 hover:ring-4 hover:ring-indigo-300 relative group/avatar ${m.role === 'head' ? 'bg-indigo-100 text-indigo-700' :
                                                m.role === 'spouse' ? 'bg-pink-100 text-pink-700' :
                                                    m.role === 'elder' ? 'bg-orange-100 text-orange-700' :
                                                        m.role === 'child' ? 'bg-emerald-100 text-emerald-700' :
                                                            'bg-slate-100 text-slate-600'
                                                }`}
                                        >
                                            {m.role === 'child' && m.age < 5 ? <Baby size={20} /> :
                                                m.role === 'elder' ? <Accessibility size={20} /> :
                                                    m.role === 'head' ? <User size={20} /> :
                                                        m.role === 'spouse' ? <Heart size={20} /> :
                                                            <User size={20} />}
                                            <div className="absolute -bottom-1 -right-1 bg-white p-1 rounded-lg shadow-md border border-slate-100 group-hover/avatar:scale-110 transition-transform">
                                                <BookOpen size={10} className="text-emerald-500" />
                                            </div>
                                        </button>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center justify-between">
                                                <p className="font-black text-slate-800 dark:text-slate-200 leading-tight truncate">{m.name || m.firstName}</p>
                                                <button
                                                    onClick={() => navigate('archive', { familyId: family.id, memberId: m.id })}
                                                    className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-tighter hover:underline"
                                                >
                                                    Detail Folder
                                                </button>
                                            </div>
                                            <p className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-tight">
                                                {m.age} th • {m.gender === 'L' ? 'Laki-laki' : 'Perempuan'} • {m.occupation}
                                            </p>
                                        </div>
                                    </div>
                                    {hasConditions && (
                                        <div className="flex flex-wrap gap-1.5 pt-2 border-t border-amber-100/50">
                                            {profile.conditions.map((c, idx) => (
                                                <span
                                                    key={idx}
                                                    className="text-[9px] px-2 py-1 rounded-md font-black uppercase tracking-tight bg-amber-200 text-amber-900"
                                                >
                                                    {c.replace(/_/g, ' ').replace('stage1', '').replace('stage2', '').replace('type2', '')}
                                                </span>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            <div className="space-y-2">
                <h4 className="font-bold text-sm text-slate-600 uppercase">Indikator 12 PIS-PK</h4>
                <div className="grid grid-cols-1 gap-2 max-h-60 overflow-y-auto pr-2 scrollbar-hide">
                    {PISPK_INDICATORS.map(ind => {
                        const isHealthy = indicators[ind.id];
                        return (
                            <div key={ind.id} className="flex items-start gap-3 py-2 border-b border-black/5 dark:border-white/5 last:border-0">
                                <div className={`mt-0.5 w-4 h-4 rounded-full shrink-0 flex items-center justify-center text-[10px] font-black
                                    ${isHealthy ? 'bg-emerald-500/20 text-emerald-400' : 'bg-red-500/20 text-red-400'}
                                `}>
                                    {isHealthy ? '✓' : '✕'}
                                </div>
                                <span className={`text-[11px] font-extrabold leading-tight ${isHealthy ? 'text-slate-700 dark:text-slate-300' : 'text-rose-700 dark:text-rose-400'}`}>
                                    {ind.label}
                                </span>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

