        adapted += '... itu lho dok, bener-bener ngeganggu saya banget. Saya sampai nggak bisa apa-apa.';
    } else if (style === 'vague') {
        if (Math.random() < 0.3) adapted = 'Ya gitu deh dok... pokoknya nggak enak banget.';
    }

    // Applying Demeanor
    if (demeanor.indexOf('anxious') !== -1 || demeanor.indexOf('cemas') !== -1) {
        adapted = adapted.replace(/\./g, '... ') + ' Duh, gimana ya Dok? Saya takut parah.';
    } else if (demeanor.indexOf('stoic') !== -1) {
        adapted = (adapted.split('.')[0] || adapted) + '. (tampak datar)';
